firmware_template.source:
#include "mqtt_ha.h"
#include <WiFi.h>
#include <PubSubClient.h>
#include <ArduinoJson.h>
static WiFiClient _wc;
static PubSubClient _mq(_wc);
static String _dev;
void ha_setup(const char*srv,const char*dev){_dev=String(dev);_mq.setServer(srv,1883);Serial.printf("[ha] OK -> %s\n",srv);}
void ha_loop(){if(!_mq.connected()){String id="parakram-"+_dev;_mq.connect(id.c_str());}_mq.loop();}
void ha_publish_sensor(const char*name,float v,const char*unit){String topic="homeassistant/sensor/"+_dev+"_"+String(name)+"/state";JsonDocument doc;doc["value"]=v;doc["unit"]=unit;String payload;serializeJson(doc,payload);_mq.publish(topic.c_str(),payload.c_str());}
void ha_publish_switch(const char*name,bool s){String topic="homeassistant/switch/"+_dev+"_"+String(name)+"/state";_mq.publish(topic.c_str(),s?"ON":"OFF");}
